package genxsolution.vms.vmsbackend.vehicle_management.vehicle_category.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_category.dto.*; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_category.service.VehicleCategoryService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/categories") public class VehicleCategoryController { private final VehicleCategoryService service; public VehicleCategoryController(VehicleCategoryService service){this.service=service;} @GetMapping public List<VehicleCategoryResponse> list(@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(), filters, Set.of()); } @GetMapping("/options") public List<VehicleCategoryOptionResponse> options(@RequestParam(required = false) String q, @RequestParam(defaultValue = "true") boolean activeOnly, @RequestParam(defaultValue = "50") int limit){ return service.options(q, activeOnly, limit); } @GetMapping("/{id}") public VehicleCategoryResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public VehicleCategoryResponse create(@RequestBody VehicleCategoryUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public VehicleCategoryResponse update(@PathVariable UUID id,@RequestBody VehicleCategoryUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
